func newAnalyticsCmd(flags *rootFlags) *cobra.Command {
	var period string
	var topN int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "analytics",
		Short: "Analyze synced Domino's order history",
		Long: `Aggregate locally synced Domino's order history into spending trends,
favorite items, order cadence, and service mix.

Order history must already exist in the local SQLite store.`,
		Example: `  # Last 30 days
  dominos-pp-cli analytics

  # Last 7 days
  dominos-pp-cli analytics --period 7d

  # Full history as JSON
  dominos-pp-cli analytics --period all --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if dbPath == "" {
				dbPath = defaultDBPath("dominos-pp-cli")
			}

			if _, err := os.Stat(dbPath); os.IsNotExist(err) {
				fmt.Fprintln(cmd.OutOrStdout(), "No order history found. Use 'orders place-order' or import history first.")
				return nil
			}

			db, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w", err)
			}
			defer db.Close()

			window, err := analyticsParsePeriod(period, time.Now().UTC())
			if err != nil {
				return err
			}

			orders, totalHistory, err := analyticsLoadOrders(db)
			if err != nil {
				return err
			}
			if totalHistory == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No order history found. Use 'orders place-order' or import history first.")
				return nil
			}

			filtered := analyticsFilterOrders(orders, window)
			if len(filtered) == 0 {
				fmt.Fprintf(cmd.OutOrStdout(), "No orders found for %s.\n", analyticsPeriodLabel(window))
				return nil
			}

			itemNames, _ := analyticsLoadItemNames(db)
			storeNames, _ := analyticsLoadStoreNames(db)
			analyticsApplyNames(filtered, itemNames, storeNames)

			out := analyticsSummarize(filtered, window, topN)
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return flags.printJSON(cmd, out)
			}
			return analyticsPrintHuman(cmd, out)
		},
	}

	cmd.Flags().StringVar(&period, "period", "30d", "Time window: 7d, 30d, 90d, or all")
	cmd.Flags().IntVar(&topN, "top", 10, "Top N items to show")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")

	return cmd
}

type analyticsPeriodWindow struct {
	Raw    string
	Cutoff *time.Time
	Days   float64
}

func analyticsParsePeriod(raw string, now time.Time) (analyticsPeriodWindow, error) {
	raw = strings.TrimSpace(strings.ToLower(raw))
	if raw == "" {
		raw = "30d"
	}
	if raw == "all" {
		return analyticsPeriodWindow{Raw: raw}, nil
	}
	if !strings.HasSuffix(raw, "d") {
		return analyticsPeriodWindow{}, fmt.Errorf("invalid --period %q: must be 7d, 30d, 90d, or all", raw)
	}
	days, err := strconv.Atoi(strings.TrimSuffix(raw, "d"))
	if err != nil || days <= 0 {
		return analyticsPeriodWindow{}, fmt.Errorf("invalid --period %q: must be 7d, 30d, 90d, or all", raw)
	}
	cutoff := now.Add(-time.Duration(days) * 24 * time.Hour)
	return analyticsPeriodWindow{
		Raw:    raw,
		Cutoff: &cutoff,
		Days:   float64(days),
	}, nil
}

func analyticsPeriodLabel(window analyticsPeriodWindow) string {
	if window.Raw == "all" {
		return "all time"
	}
	return "last " + window.Raw
}

func analyticsLoadOrders(db *store.Store) ([]analyticsOrder, int, error) {
	const maxRows = 1000000
	resourceTypes := []string{"order_history", "order"}

	orders := make([]analyticsOrder, 0)
	seen := map[string]struct{}{}
	totalHistory := 0

	for _, resourceType := range resourceTypes {
		items, err := db.List(resourceType, maxRows)
		if err != nil {
			return nil, 0, fmt.Errorf("reading %s: %w", resourceType, err)
		}
		totalHistory += len(items)
		for _, item := range items {
			order, ok := analyticsParseOrder(item)
			if !ok {
				continue
			}
			key := order.ID
			if key == "" {
				key = order.StoreID + "|" + order.CreatedAt.UTC().Format(time.RFC3339Nano) + "|" + fmt.Sprintf("%.2f", order.Total)
			}
			if _, exists := seen[key]; exists {
				continue
			}
			seen[key] = struct{}{}
			orders = append(orders, order)
		}
	}

	sort.Slice(orders, func(i, j int) bool {
		return orders[i].CreatedAt.After(orders[j].CreatedAt)
	})
	return orders, totalHistory, nil
}

func analyticsParseOrder(raw json.RawMessage) (analyticsOrder, bool) {
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return analyticsOrder{}, false
	}

	source := analyticsOrderObject(obj)
	createdAt, ok := analyticsExtractTime(obj, source)
	if !ok {
		return analyticsOrder{}, false
	}

	total, ok := analyticsExtractTotal(obj, source)
	if !ok {
		return analyticsOrder{}, false
	}

	products := analyticsExtractProducts(obj, source)
	return analyticsOrder{
		ID:            analyticsFirstString(obj, source, "OrderID", "orderId", "ID", "id"),
		StoreID:       analyticsFirstString(obj, source, "StoreID", "StoreId", "store_id", "storeId"),
		StoreName:     analyticsFirstString(obj, source, "StoreName", "store_name", "Store", "store"),
		ServiceMethod: analyticsFirstString(obj, source, "ServiceMethod", "service_method", "serviceMethod"),
		CreatedAt:     createdAt,
		Total:         total,
		Products:      products,
	}, true
}

func analyticsOrderObject(obj map[string]any) map[string]any {
	if nested, ok := obj["Order"].(map[string]any); ok {
		return nested
	}
	if nested, ok := obj["order"].(map[string]any); ok {
		return nested
	}
	return obj
}

func analyticsExtractTime(objects ...map[string]any) (time.Time, bool) {
	for _, key := range []string{"CreatedAt", "created_at", "Timestamp", "timestamp", "OrderDate", "order_date"} {
		for _, obj := range objects {
			if ts, ok := analyticsParseAnyTime(obj[key]); ok {
				return ts, true
			}
		}
	}
	return time.Time{}, false
}

func analyticsParseAnyTime(v any) (time.Time, bool) {
	switch x := v.(type) {
	case string:
		s := strings.TrimSpace(x)
		if s == "" {
			return time.Time{}, false
		}
		for _, layout := range []string{
			time.RFC3339Nano,
			time.RFC3339,
			"2006-01-02T15:04:05",
			"2006-01-02 15:04:05",
			"2006-01-02",
		} {
			if ts, err := time.Parse(layout, s); err == nil {
				return ts.UTC(), true
			}
		}
		if n, err := strconv.ParseInt(s, 10, 64); err == nil {
			return analyticsUnixTime(n)
		}
	case float64:
		return analyticsUnixTime(int64(x))
	case int64:
		return analyticsUnixTime(x)
	case json.Number:
		if n, err := x.Int64(); err == nil {
			return analyticsUnixTime(n)
		}
	}
	return time.Time{}, false
}

func analyticsUnixTime(n int64) (time.Time, bool) {
	if n <= 0 {
		return time.Time{}, false
	}
	if n > 1_000_000_000_000 {
		return time.UnixMilli(n).UTC(), true
	}
	return time.Unix(n, 0).UTC(), true
}

func analyticsExtractTotal(objects ...map[string]any) (float64, bool) {
	for _, obj := range objects {
		if amount := analyticsNestedFloat(obj, "AmountsBreakdown", "Customer"); amount > 0 {
			return amount, true
		}
		if amount := analyticsNestedFloat(obj, "amounts_breakdown", "customer"); amount > 0 {
			return amount, true
		}
		if amount, ok := comparePricesFloat(obj["Customer"]); ok && amount > 0 {
			return amount, true
		}
		if amount, ok := comparePricesFloat(obj["Total"]); ok && amount > 0 {
			return amount, true
		}
		if amount, ok := comparePricesFloat(obj["total"]); ok && amount > 0 {
			return amount, true
		}
	}
	return 0, false
}

func analyticsNestedFloat(obj map[string]any, parent, child string) float64 {
	node, ok := obj[parent].(map[string]any)
	if !ok {
		return 0
	}
	value, _ := comparePricesFloat(node[child])
	return value
}

func analyticsExtractProducts(objects ...map[string]any) []analyticsProduct {
	for _, obj := range objects {
		raw, ok := obj["Products"]
		if !ok {
			raw = obj["products"]
		}
		items, ok := raw.([]any)
		if !ok {
			continue
		}
		products := make([]analyticsProduct, 0, len(items))
		for _, item := range items {
			productObj, ok := item.(map[string]any)
			if !ok {
				continue
			}
			code := analyticsFirstString(productObj, nil, "Code", "code", "ProductCode", "product_code")
			if code == "" {
				continue
			}
			qty := 1
			if q, ok := comparePricesFloat(productObj["Qty"]); ok && q > 0 {
				qty = int(q)
			} else if q, ok := comparePricesFloat(productObj["qty"]); ok && q > 0 {
				qty = int(q)
			} else if q, ok := comparePricesFloat(productObj["Quantity"]); ok && q > 0 {
				qty = int(q)
			}
			products = append(products, analyticsProduct{
				Code: code,
				Name: analyticsFirstString(productObj, nil, "Name", "name"),
				Qty:  qty,
			})
		}
		return products
	}
	return nil
}

func analyticsFirstString(primary map[string]any, secondary map[string]any, keys ...string) string {
	for _, obj := range []map[string]any{primary, secondary} {
		if obj == nil {
			continue
		}
		for _, key := range keys {
			if value := comparePricesString(obj[key]); value != "" {
				return value
			}
		}
	}
	return ""
}

func analyticsFilterOrders(orders []analyticsOrder, window analyticsPeriodWindow) []analyticsOrder {
	if window.Cutoff == nil {
		return orders
	}
	filtered := make([]analyticsOrder, 0, len(orders))
	for _, order := range orders {
		if order.CreatedAt.IsZero() || order.CreatedAt.Before(*window.Cutoff) {
			continue
		}
		filtered = append(filtered, order)
	}
	return filtered
}

func analyticsLoadItemNames(db *store.Store) (map[string]string, error) {
	const maxRows = 1000000
	items, err := db.List("menu_snapshot", maxRows)
	if err != nil {
		return nil, err
	}
	names := map[string]string{}
	for _, item := range items {
		var snapshot map[string]any
		if err := json.Unmarshal(item, &snapshot); err != nil {
			continue
		}
		menuRaw, ok := snapshot["Menu"]
		if !ok {
			menuRaw = snapshot["menu"]
		}
		menu, ok := menuRaw.(map[string]any)
		if !ok {
			continue
		}
		analyticsCollectItemNames(names, menu["Variants"])
		analyticsCollectItemNames(names, menu["Products"])
		analyticsCollectItemNames(names, menu["variants"])
		analyticsCollectItemNames(names, menu["products"])
	}
	return names, nil
}

func analyticsCollectItemNames(dst map[string]string, raw any) {
	nodes, ok := raw.(map[string]any)
	if !ok {
		return
	}
	for code, value := range nodes {
		obj, ok := value.(map[string]any)
		if !ok {
			continue
		}
		itemCode := analyticsFirstString(obj, nil, "Code", "code")
		if itemCode == "" {
			itemCode = code
		}
		name := analyticsFirstString(obj, nil, "Name", "name")
		if itemCode != "" && name != "" && dst[itemCode] == "" {
			dst[itemCode] = name
		}
	}
}

func analyticsLoadStoreNames(db *store.Store) (map[string]string, error) {
	const maxRows = 1000000
	items, err := db.List("stores", maxRows)
	if err != nil {
		return nil, err
	}
	names := map[string]string{}
	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			continue
		}
		storeID := analyticsFirstString(obj, nil, "StoreID", "StoreId", "store_id", "storeId", "ID", "id")
		if storeID == "" {
			continue
		}
		name := analyticsFirstString(obj, nil, "Name", "name", "StoreName", "store_name")
		if name != "" && names[storeID] == "" {
			names[storeID] = name
		}
	}
	return names, nil
}

func analyticsApplyNames(orders []analyticsOrder, itemNames, storeNames map[string]string) {
	for i := range orders {
		if orders[i].StoreName == "" {
			orders[i].StoreName = storeNames[orders[i].StoreID]
		}
		for j := range orders[i].Products {
			if orders[i].Products[j].Name == "" {
				orders[i].Products[j].Name = itemNames[orders[i].Products[j].Code]
			}
		}
	}
}

func analyticsSummarize(orders []analyticsOrder, window analyticsPeriodWindow, topN int) analyticsOutput {
	if topN <= 0 {
		topN = 10
	}

	var totalSpent float64
	deliveryOrders := 0
	carryoutOrders := 0
	itemCounts := map[string]*analyticsItemCount{}
	storeCounts := map[string]*analyticsFavoriteStore{}

	earliest := orders[0].CreatedAt
	latest := orders[0].CreatedAt
	for _, order := range orders {
		totalSpent += order.Total
		if order.CreatedAt.Before(earliest) {
			earliest = order.CreatedAt
		}
		if order.CreatedAt.After(latest) {
			latest = order.CreatedAt
		}

		switch analyticsNormalizeService(order.ServiceMethod) {
		case "delivery":
			deliveryOrders++
		case "carryout":
			carryoutOrders++
		}

		storeKey := order.StoreID
		if storeKey == "" {
			storeKey = "unknown"
		}
		favStore := storeCounts[storeKey]
		if favStore == nil {
			favStore = &analyticsFavoriteStore{ID: order.StoreID, Name: order.StoreName}
			storeCounts[storeKey] = favStore
		}
		if favStore.Name == "" {
			favStore.Name = order.StoreName
		}
		favStore.Orders++

		for _, product := range order.Products {
			item := itemCounts[product.Code]
			if item == nil {
				item = &analyticsItemCount{Code: product.Code, Name: product.Name}
				itemCounts[product.Code] = item
			}
			if item.Name == "" {
				item.Name = product.Name
			}
			item.TimesOrdered += product.Qty
		}
	}

	orderCount := len(orders)
	avgOrderValue := 0.0
	if orderCount > 0 {
		avgOrderValue = totalSpent / float64(orderCount)
	}

	periodDays := window.Days
	if periodDays == 0 {
		periodDays = latest.Sub(earliest).Hours()/24 + 1
		if periodDays < 1 {
			periodDays = 1
		}
	}
	frequencyPerWeek := float64(orderCount) / periodDays * 7
	frequencyPerMonth := float64(orderCount) / periodDays * 30

	items := make([]analyticsItemCount, 0, len(itemCounts))
	for _, item := range itemCounts {
		items = append(items, *item)
	}
	sort.Slice(items, func(i, j int) bool {
		if items[i].TimesOrdered == items[j].TimesOrdered {
			return items[i].Code < items[j].Code
		}
		return items[i].TimesOrdered > items[j].TimesOrdered
	})
	if topN > len(items) {
		topN = len(items)
	}
	favoriteItems := make([]analyticsFavoriteItem, 0, topN)
	for i := 0; i < topN; i++ {
		favoriteItems = append(favoriteItems, analyticsFavoriteItem{
			Rank:         i + 1,
			Code:         items[i].Code,
			Name:         items[i].Name,
			TimesOrdered: items[i].TimesOrdered,
		})
	}

	favoriteStore := analyticsFavoriteStore{}
	for _, candidate := range storeCounts {
		if candidate.Orders > favoriteStore.Orders || (candidate.Orders == favoriteStore.Orders && candidate.ID < favoriteStore.ID) {
			favoriteStore = *candidate
		}
	}

	serviceMix := analyticsServiceMix{}
	if orderCount > 0 {
		serviceMix.Delivery = float64(deliveryOrders) / float64(orderCount) * 100
		serviceMix.Carryout = float64(carryoutOrders) / float64(orderCount) * 100
	}

	return analyticsOutput{
		Period: analyticsPeriodLabel(window),
		Summary: analyticsSummary{
			TotalOrders:       orderCount,
			TotalSpent:        totalSpent,
			AvgOrderValue:     avgOrderValue,
			FrequencyPerWeek:  frequencyPerWeek,
			FrequencyPerMonth: frequencyPerMonth,
			ServiceMix:        serviceMix,
		},
		FavoriteItems: favoriteItems,
		FavoriteStore: favoriteStore,
	}
}

func analyticsNormalizeService(raw string) string {
	value := strings.ToLower(strings.TrimSpace(raw))
	switch value {
	case "delivery":
		return "delivery"
	case "carryout", "carry out", "pickup", "pick-up":
		return "carryout"
	default:
		return value
	}
}

func analyticsPrintHuman(cmd *cobra.Command, out analyticsOutput) error {
	w := cmd.OutOrStdout()
	fmt.Fprintf(w, "== Domino's %s ==\n", out.Period)
	fmt.Fprintf(w, "Orders:         %d\n", out.Summary.TotalOrders)
	fmt.Fprintf(w, "Total spent:    $%.2f\n", out.Summary.TotalSpent)
	fmt.Fprintf(w, "Avg order:      $%.2f\n", out.Summary.AvgOrderValue)
	fmt.Fprintf(w, "Frequency:      %.1f/week (%.1f/month)\n", out.Summary.FrequencyPerWeek, out.Summary.FrequencyPerMonth)
	fmt.Fprintf(w, "Service mix:    %.0f%% delivery, %.0f%% carryout\n", out.Summary.ServiceMix.Delivery, out.Summary.ServiceMix.Carryout)
	if out.FavoriteStore.ID != "" {
		if out.FavoriteStore.Name != "" {
			fmt.Fprintf(w, "Favorite store: %s (%s) - %d orders\n", out.FavoriteStore.ID, out.FavoriteStore.Name, out.FavoriteStore.Orders)
		} else {
			fmt.Fprintf(w, "Favorite store: %s - %d orders\n", out.FavoriteStore.ID, out.FavoriteStore.Orders)
		}
	}

	if len(out.FavoriteItems) == 0 {
		return nil
	}

	fmt.Fprintln(w)
	fmt.Fprintf(w, "Top %d items:\n", len(out.FavoriteItems))
	tw := tabwriter.NewWriter(w, 2, 4, 2, ' ', 0)
	fmt.Fprintln(tw, "Rank\tCode\tName\tTimes Ordered")
	for _, item := range out.FavoriteItems {
		fmt.Fprintf(tw, "%d\t%s\t%s\t%d\n", item.Rank, item.Code, item.Name, item.TimesOrdered)
	}
	return tw.Flush()
}
